local LGpBaseMgr      = LxRequire("LApp.gameplay.Base.LGpBaseMgr")
---@class LDefenceWarManager: LGpBaseMgr
local LDefenceWarManager = LxClass("LDefenceWarManager", LGpBaseMgr)

local LFightIdleHudCtrl     = LXImport("LApp.gameplay.fightIdle.Ctrl.LFightIdleHudCtrl")
local LFightIdleHudData     = LxRequire("LApp.gameplay.fightIdle.Data.LFightIdleHudData")

local Objs               = LXImport(".Ctrl.LDefenceWarObjsCtrl")
local Hud                = LXImport(".Ctrl.LDefenceWarHudCtrl")
local Hero               = LXImport(".Ctrl.LDefenceWarHeroCtrl")
local EffPool            = LXImport(".Ctrl.LDefenceWarEffPoolCtrl")


--
local CtrlList   = {
    { key = "EffPool", class = EffPool },
    { key = "Objs",    class = Objs },
    { key = "Hud",     class = Hud },
    { key = "Hero",    class = Hero },
}

local Tweening   = DG.Tweening
local Ease       = Tweening.Ease
local Quaternion = Quaternion
local Vector3    = Vector3
local math       = math
local Time       = Time


function LDefenceWarManager:LDefenceWarManager()
    -- LDefenceWarMap
    self._map = nil

    self._pause = true

    -- 控制类
    self._ctrlMaps = {}

    self._inMap = true

    -- 游戏时间
    self._gameTime = nil

    self._hubObjIndexList = {}

    self._checkTime = 0

    self._hudScale = Vector3(0.65, 0.65, 0.65)

    self:InitEvent()
    self:DelayFuncClear()
end

function LDefenceWarManager:Destroy()
    LGpBaseMgr.Destroy(self)
end

-- region 数据 ----------------------------------------------------

-- 初始化数据
function LDefenceWarManager:InitData(stageId)
    -- 正在挑战的关卡
    self._playingStageId = stageId

    -- 怪物设置列表
    self._monsterSettingList = {}

    -- 怪物总数
    self._monsterTatal = 0

    -- 怪物死亡数
    self._monsterDead = 0

    -- 怪物波数
    self._monsterWaveMax = 0

    -- 当前波数
    self._monsterWave = 0

    -- 核心最大生命
    self._curHpMax = gModelDefenceWar:GetCoreMaxHp() + gModelDefenceWar:GetInitCoreHp()

    -- 当前核心生命
    self._curHp = self._curHpMax

    self:InitMonsterList()

    self._gameOver = nil
end

-- 当前正在挑战的关卡ID
function LDefenceWarManager:GetPlayingStageId()
    return self._playingStageId
end

-- 初始化怪物列表
function LDefenceWarManager:InitMonsterList()
    self._monsterSettingList = {}

    local stageRefId = self:GetPlayingStageId()
    local ref = gModelDefenceWar:GetStageRef(stageRefId)

    self._maxLev = ref.levelMax

    local groupId = ref.monster
    local total = 0

    local dataList = gModelDefenceWar:GetMonsterListFromMonsterGroup(groupId)
    for _, list in ipairs(dataList) do
        total = total + #list

        table.insert(self._monsterSettingList, list)
    end

    self._monsterTatal = total
    self._monsterWaveMax = #self._monsterSettingList
    self._monsterWave = 0
end

-- endregion 数据 ----------------------------------------------------

-- 进入地图
function LDefenceWarManager:EnterMap(map, stageId)
    self._map = map
    self._inMap = true

    self:InitData(stageId)
    self:InitCtrls()

    self:SaveTimeScale()
    self:SetTimeScale(1)
end

-- 退出地图
function LDefenceWarManager:ExitMap()
    self._inMap = nil
    self._pause = true

    self:ResumeByTimeScale()
    self:DelayFuncClear()
    self:DeleteCtrl()
    if self._oldTimeScale then
        self:SetTimeScale(self._oldTimeScale)
        self._oldTimeScale = nil
    end
end

function LDefenceWarManager:InitEvent()
    self:EventRecv(EventNames.DEFENCEWAR_SKILL_SELECT, function(...)
        if not self._inMap then
            return
        end
        self:OnSkillSelect(...)
    end)
end

-- true:表示退出地图
function LDefenceWarManager:IsExit()
    return self._inMap == nil
end

-- 重新开始游戏
function LDefenceWarManager:RestartGame(stageId)
    self:ExitMap()
    self:EnterMap(self._map, stageId)

    LxTimer.DelayTimeCall(function()
        if not self._inMap then
            return
        end
        self:StartGame()
    end, 0.3)
end

-- 开始游戏
function LDefenceWarManager:StartGame()
    if LOG_INFO_ENABLED then
        gModelDefenceWar:Log("开始游戏")
    end
    self._gameTime = 0
    self._checkReadyMonsterTime = 0.5
    self:SetPause(false)

    FireEvent(EventNames.DEFENCEWAR_GAME_START)
end

-- 初始化控制类
function LDefenceWarManager:InitCtrls()
    for _, tab in ipairs(CtrlList) do
        local ctrl = tab.class:New(self, self._map)
        ctrl:Init()
        self._ctrlMaps[tab.key] = ctrl
    end

    self._hudCtrl = LFightIdleHudCtrl:New(self)
    self._hudCtrl:InitHud()
end

-- 删除控制类
function LDefenceWarManager:DeleteCtrl()
    for _, ctrl in pairs(self._ctrlMaps) do
        ctrl:Destroy()
    end
    self._ctrlMaps = {}

    if self._hudCtrl then
        self._hudCtrl:Destroy()
        self._hudCtrl = nil
    end
end

-- 获取控制类
function LDefenceWarManager:GetCtrl(name)
    return self._ctrlMaps[name]
end

-- region 伤害票字 ----------------------------------------------------
--
-- 伤害飘字
function LDefenceWarManager:ApplyHurt(obj, hurt, changeType)
    if not self._hudCtrl then return end

    self:CheckHurtIndex()

    local hudDataList = self:CalcHurtWaveData(changeType, hurt, obj)

    self._hudCtrl:CreateHud(obj, hudDataList)
end

-- 组织 飘字数据结构
function LDefenceWarManager:GenerateHudData(obj, changeType, hurt, delay, floatHurtY, floatHurtXMin, floatHurtXMax)
    local data = LFightIdleHudData:New(changeType, hurt, delay, floatHurtY, floatHurtXMin, floatHurtXMax)

    if not self._hubObjIndexList[obj] then
        local list = {}
        list[0] = 1
        list[1] = 1
        self._hubObjIndexList[obj] = list
    elseif #self._hubObjIndexList[obj] > 8 then
        local list = {}
        list[0] = 1
        list[1] = 1
        self._hubObjIndexList[obj] = list
    else
        table.insert(self._hubObjIndexList[obj], 1)
    end

    data:SetIndex(#self._hubObjIndexList[obj])
    data:SetScale(self._hudScale)

    return data
end

-- 组织 飘字数据结构
function LDefenceWarManager:CalcHurtWaveData(changeType, hurt, obj)
    local offsetY = -80
    return { self:GenerateHudData(obj, changeType, hurt, 0, offsetY, -20, 20) }
end

-- 清理列表，防止列表过大
function LDefenceWarManager:CheckHurtIndex()
    if self._checkTime < os.time() then
        self._checkTime = os.time() + 10

        local list = {}
        for k, v in pairs(self._hubObjIndexList) do
            list[k] = v
        end
        self._hubObjIndexList = list
    end
end

-- endregion 伤害票字 ----------------------------------------------------

-- update
function LDefenceWarManager:Update(dt)
    if self._pause then
        return
    end

    for k, v in pairs(self._delayFuncMap) do
        v.time = v.time - dt
        if v.time <= 0 then
            v.func()
            self._delayFuncMap[k] = nil
        end
    end


    if self._gameTime then
        self._gameTime = self._gameTime + dt

        if self._gameTime >= self._checkReadyMonsterTime then
            self:ReadyMonster()
        end
    end

    for _, ctrl in pairs(self._ctrlMaps) do
        if ctrl.Update then
            ctrl:Update(dt)
        end
    end

    if self._hudCtrl then
        self._hudCtrl:OnRun(Time.time)
    end

    for k, v in pairs(self._hubObjIndexList) do
        v[0] = v[0] - dt
        if v[0] < 0 then
            self._hubObjIndexList[k] = nil
        end
    end
end

-- 准备生产怪物
function LDefenceWarManager:ReadyMonster()
    if self._monsterWave == self._monsterWaveMax then
        return
    end

    local objsCtrl = self:GetCtrl("Objs")
    local wave = self._monsterWave + 1

    local list = self._monsterSettingList[wave]
    objsCtrl:ReadyCreateMonster(list)
    self._monsterWave = wave

    local nextWave = wave + 1
    if nextWave < self._monsterWaveMax then
        local list = self._monsterSettingList[nextWave]
        local tab = list[1]
        local groupRef = gModelDefenceWar:GetMonsterGroupRef(tab.groupRefId)
        self._checkReadyMonsterTime = self._gameTime + groupRef.starTime
    end
    FireEvent(EventNames.DEFENCEWAR_MONSTER_WAVE)
end

-- 获取怪物波次
function LDefenceWarManager:GetMonsterWave()
    return self._monsterWave, self._monsterWaveMax
end

-- 设置暂停
function LDefenceWarManager:SetPause(bool)
    self._pause = bool

    local objsCtrl = self:GetCtrl("Objs")
    local heroCtrl = self:GetCtrl("Hero")
    if bool then
        objsCtrl:OnPauseGame()
        heroCtrl:OnPauseGame()
    else
        objsCtrl:OnResumeGame()
        heroCtrl:OnResumeGame()
    end

    if LOG_INFO_ENABLED then
        gModelDefenceWar:Log("设置暂停:" .. tostring(bool))
    end
end

-- unity时间： Time.time
function LDefenceWarManager:GetTime()
    return Time.time
end

-- 保存timeScale
function LDefenceWarManager:SaveTimeScale()
    self._oldTimeScale = Time.timeScale
end

-- 恢复timeScale
function LDefenceWarManager:ResumeByTimeScale()
    -- Time.timeScale = self._curTimeScale
end

-- 通过timeScale 暂停
function LDefenceWarManager:PauseByTimeScale()
    -- Time.timeScale = 0
end

