end

-- true: 在锁定
function LDefenceWarManager:IsPause()
    return self._pause
end

-- 延迟函数 -- todo: 优化清理掉此用法
function LDefenceWarManager:DelayFunc(func, delayTime, key)
    if not key then
        self._delayFuncIndex = self._delayFuncIndex + 1
        key = self._delayFuncIndex
    end
    self._delayFuncMap = self._delayFuncMap or {}
    self._delayFuncMap[key] = { func = func, time = delayTime }
end

-- 删除延迟函数
function LDefenceWarManager:DeleteDelayFunc(key)
    self._delayFuncMap[key] = nil
end

-- 清除延迟函数
function LDefenceWarManager:DelayFuncClear()
    self._delayFuncIndex = 0
    self._delayFuncMap = {}
end

-- 弹出技能选择
function LDefenceWarManager:ShowSkillSelect()
    if LOG_INFO_ENABLED then
        gModelDefenceWar:Log("弹出技能选择")
    end

    self:SetPause(true)
    local skillList = self:GetRandomSkillList()
    gModelDefenceWar:ShowSkillSelect(skillList)
end

-- 技能选择完成
function LDefenceWarManager:OnSkillSelect(data)
    if LOG_INFO_ENABLED then
        gModelDefenceWar:Log("技能选择完成")
    end

    local heroCtrl = self:GetCtrl("Hero")
    heroCtrl:AddOrUpdateSkill(data.heroId, data.skillId, data.skillLev)

    FireEvent(EventNames.DEFENCEWAR_SKILL_SELECT_FINISH)
end

-- 获取随技能列表
function LDefenceWarManager:GetRandomSkillList()
    local heroCtrl = self:GetCtrl("Hero")
    return heroCtrl:GetRandomSkillList()
end

-- 计算技能伤害目标列表
function LDefenceWarManager:CalcSkillHurtTargetList(skillObj, targetList)
    local totalHurt = 0

    local atk = skillObj:GetAtk()
    local hudCtrl = self:GetCtrl("Hud")
    local objsCtrl = self:GetCtrl("Objs")

    local hadDead = false

    local totalExp = 0
    for _, obj in ipairs(targetList) do
        local objData = obj:GetData()
        local def = objData:GetDef()
        local hp = objData:GetHp()
        local hurt = math.ceil(atk - def)
        objData:SetHp(hp - hurt)

        obj:ShowBloodStick()

        totalHurt = totalHurt + hurt

        -- 显示伤害
        -- local trans = obj:GetTransform()
        -- local pos = trans.position
        -- hudCtrl:ShowHud(pos, -hurt, 0, obj:GetIndex())
        self:ApplyHurt(obj, hurt, 1)

        if objData:GetHp() <= 0 then
            -- 死亡
            totalExp = totalExp + objData:GetExp()

            hadDead = true

            self._monsterDead = self._monsterDead + 1

            obj:PlayDead(0.2)
        end
    end

    skillObj:GetObj():AddHurt(totalHurt)
    FireEvent(EventNames.DEFENCEWAR_HERO_HURT)

    if hadDead then
        if objsCtrl:GetMonsterCount() == 0 and objsCtrl:GetReadyCreateMonsterCount() == 0 then
            local wave, waveMax = self:GetMonsterWave()
            if wave == waveMax then
                self:DelayFunc(function()
                    self:GameOver(true)
                end, 0.6)
                return
            end

            self._checkReadyMonsterTime = self._gameTime
        end
        self:AddExp(totalExp)
    end
end

-- 增加经验
function LDefenceWarManager:AddExp(totalExp)
    FireEvent(EventNames.DEFENCEWAR_MAP_LEVUP, { addExp = totalExp })
end

-- 获取英雄伤害列表
function LDefenceWarManager:GetHeroHurtList()
    local heroCtrl = self:GetCtrl("Hero")
    return heroCtrl:GetHeroHurtList()
end

-- 核心受伤
function LDefenceWarManager:CoreHurt(obj)
    local atk = obj:GetData():GetAtk()
    local hurt = atk
    local curHp = self._curHp - hurt
    if curHp <= 0 then
        curHp = 0
    end
    self._curHp = curHp
    FireEvent(EventNames.DEFENCEWAR_CORE_HURT, { hurt = hurt })

    if curHp == 0 then
        self:GameOver(false)
    end
end

-- 游戏结束
function LDefenceWarManager:GameOver(isWin)
    if LOG_INFO_ENABLED then
        gModelDefenceWar:Log("游戏结束")
    end
    if self._gameOver then
        return
    end
    self._gameOver = true

    self:SetPause(true)
    self:DelayFuncClear()

    local stageId = self:GetPlayingStageId()
    local ispassed = isWin and 1 or 0
    local hurtNum = 0
    local heroHurtList = self:GetHeroHurtList()
    for _, v in ipairs(heroHurtList) do
        hurtNum = hurtNum + v.hurt
    end

    local process = 100
    if not isWin then
        process = math.floor(self._monsterDead / self._monsterTatal * 100)
    end
    self:ClearStorage()
    gModelDefenceWar:ProtectCityBattleResultReq(stageId, ispassed, hurtNum, process)

    FireEvent(EventNames.DEFENCEWAR_GAME_OVER, { stageId = stageId, isWin = isWin })
end

-- 清理内存
function LDefenceWarManager:ClearStorage()
    collectgarbage("collect")
    collectgarbage("collect")
    collectgarbage("collect")
    LxUnity.UResources.UnloadUnusedAssets()
end

return LDefenceWarManager
